    public void listar() throws ClassNotFoundException {
        LivroDAO dao = new LivroDAO();
        List<Livro> lista = dao.Listar();
        DefaultTableModel model = (DefaultTableModel) tabela_Livros.getModel();
        model.setNumRows(0);
        for (Livro l : lista) {
            model.addRow(new Object[] {
                l.getId(),
                l.getTitulo(),
                l.getAutor(),
                l.getAno_publicacao(),
                l.getGenero(),
                l.getIdioma(),
                l.getQuantidade(),
                l.getEditora()
            });
        }
    }
    
