    private void btnVerDetalhesActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnVerDetalhesActionPerformed
        try {
            // TODO add your handling code here:
            int linha = tabela_Livros.getSelectedRow();

            if (linha == -1) {
                JOptionPane.showMessageDialog(this, "Selecione um livro na tabela!");
                return;
            }

            int id = Integer.parseInt(tabela_Livros.getValueAt(linha, 0).toString());

            Livro obj = new Livro();
            LivroDAO dao = new LivroDAO();
            obj = dao.buscarPorId(id);

            if (obj == null) {
                JOptionPane.showMessageDialog(this, "Livro não encontrado!");
                return;
            }
            
            DetalhesLivroDialog tela = new DetalhesLivroDialog(obj, false);
            tela.setVisible(true);
        } catch (ClassNotFoundException ex) {
            Logger.getLogger(Consulta.class.getName()).log(Level.SEVERE, null, ex);
        }
    }//GEN-LAST:event_btnVerDetalhesActionPerformed

    private void btnAtualizarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnAtualizarActionPerformed
        try {
            // TODO add your handling code here:
            int linha = tabela_Livros.getSelectedRow();

            if (linha == -1) {
                JOptionPane.showMessageDialog(this, "Selecione um livro na tabela!");
                return;
            }

            int id = Integer.parseInt(tabela_Livros.getValueAt(linha, 0).toString());

            Livro obj = new Livro();
            LivroDAO dao = new LivroDAO();
            obj = dao.buscarPorId(id);

            if (obj == null) {
                JOptionPane.showMessageDialog(this, "Livro não encontrado!");
                return;
            }
            
            DetalhesLivroDialog tela = new DetalhesLivroDialog(obj, true);
            tela.setVisible(true);
        } catch (ClassNotFoundException ex) {
            Logger.getLogger(Consulta.class.getName()).log(Level.SEVERE, null, ex);
        }
    }//GEN-LAST:event_btnAtualizarActionPerformed

    private void btnEliminarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnEliminarActionPerformed
        // TODO add your handling code here:
        int linha = tabela_Livros.getSelectedRow();

        if (linha == -1) {
            JOptionPane.showMessageDialog(this, 
                "Selecione um livro para eliminar!", 
                "Atenção", 
                JOptionPane.WARNING_MESSAGE);
            return;
        }

        int id = Integer.parseInt(tabela_Livros.getValueAt(linha, 0).toString());

        int opcao = JOptionPane.showConfirmDialog(
                this,
                "Tem certeza que deseja eliminar este livro?",
                "Confirmar exclusão",
                JOptionPane.YES_NO_OPTION);

        if (opcao == JOptionPane.YES_OPTION) {

            try {
                Livro l = new Livro();
                l.setId(id);
                
                LivroDAO dao = new LivroDAO();
                dao.Eliminar(l);
            } catch (ClassNotFoundException ex) {
                Logger.getLogger(Consulta.class.getName()).log(Level.SEVERE, null, ex);
            }

        }
    }//GEN-LAST:event_btnEliminarActionPerformed

